```class Solution {
public:
    int maxPalindromes(string s, int k) {
        int n = s.size();
        vector<bool> isPalin(n, false);
        for (int i = 0; i < n; ++i) {
            if (s[i] == s[i + 1]) {
                isPalin[i] = isPalin[i + 1] = true;
            }
        }
        for (int len = 3; len <= n; len += 2) {
            for (int i = 0; i <= n - len; ++i) {
                if (s[i] == s[i + len - 1] && isPalin[i + 1]) {
                    isPalin[i] = true;
                }
            }
        }

        int res = 0;
        bool used[n] = {false};
        for (int i = 0; i < n; ) {
            if (isPalin[i] && i - k + 1 >= 0) {
                ++res;
                for (int j = i; j < i + k; ++j) {
                    used[j] = true;
                }
                i += k;
            } else {
                ++i;
            }
        }
        return res;
    }
};
